import React, { useEffect } from 'react';
import { MapContainer, TileLayer, Polyline, Marker, useMap } from 'react-leaflet';
import L from 'leaflet';

// 🛡️ THE FIX: This manually points to the marker images so they show up
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

// Helper component to make the map "jump" to the new coordinates
function RecenterMap({ coords }) {
  const map = useMap();
  useEffect(() => {
    if (coords) {
      map.setView([coords.lat, coords.lng], 14); // Zoom level 14
    }
  }, [coords, map]);
  return null;
}

const MapDisplay = ({ waypoints, source, destination }) => {
  return (
    <MapContainer 
      center={[20.5937, 78.9629]} 
      zoom={5} 
      style={{ height: '100%', width: '100%' }}
    >
      <TileLayer 
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" 
        attribution='&copy; OpenStreetMap contributors'
      />
      
      {/* Show Start Marker */}
      {source && <Marker position={[source.lat, source.lng]} />}
      
      {/* Show Destination Marker */}
      {destination && <Marker position={[destination.lat, destination.lng]} />}
      
      {/* Draw the actual road path */}
      {waypoints && waypoints.length > 0 && (
        <Polyline positions={waypoints} color="#db2777" weight={5} opacity={0.7} />
      )}
      
      {/* This component moves the camera when you search */}
      <RecenterMap coords={source} />
    </MapContainer>
  );
};

export default MapDisplay;
